import { memo } from 'react'
import styled, { css } from 'styled-components'

import { toCurrency } from '../../../../helpers'
import { Body } from '../../../../components/typography/Body'
import { Heading } from '../../../../components/typography/Heading'

const Container = styled.div<{ $isHighlighted: boolean }>(
  ({ theme: { boxShadow, color, borderRadius } }) => css`
    padding: 1.5rem;
    border-radius: ${borderRadius.xs};
    transition: box-shadow 0.1s ease-in;
    position: relative;
    background: ${color.foodItemBackground};

    &:hover {
      cursor: pointer;
      box-shadow: ${boxShadow.card};
    }
  `
)

const Quantity = styled(Body)(
  ({ theme: { color, borderRadius } }) => css`
    padding: 0.25rem;
    width: 35px;
    height: 35px;
    border-radius: ${borderRadius.xs};
    display: flex;
    align-items: center;
    justify-content: center;
    background: ${color.black};
    color: ${color.white};
    position: absolute;
    top: 0;
    right: 0;
  `
)

const Description = styled(Body)(
  ({ theme: { color } }) => `
  margin: 0;
  color: ${color.badgeText};
  margin-top: 0.5rem;
`
)

const Price = styled(Body)`
  margin: 0;
  margin-top: 1rem;
`

type FoodItemProps = {
  quantity?: number
  name: string
  price: number
  description?: string
  onClick: () => void
}

export const FoodItem = memo(
  ({ quantity = 0, name, price, description, onClick }: FoodItemProps) => (
    <Container $isHighlighted={quantity > 0} onClick={onClick}>
      <div>
        {quantity > 0 && (
          <Quantity aria-label="food quantity" type="span" fontWeight="medium">
            {quantity}
          </Quantity>
        )}
        <Heading level={4}>{name}</Heading>
        <Description>{description}</Description>
        <Price>{toCurrency(price)}</Price>
      </div>
    </Container>
  )
)
FoodItem.displayName = 'FoodItem'

import styled from 'styled-components'
import { memo } from 'react'

import { breakpoints } from '../../../../styles/breakpoints'
import { FoodItem } from '../FoodItem/FoodItem'
import type { CartItem } from '../../../../app-state/cart'
import type { FoodMenuItem } from '../../../../types'
import { Heading } from '../../../../components/typography'

type FoodSectionProps = {
  items: FoodMenuItem[]
  title: string
  cartItems: CartItem[]
  onItemClick?: (item: CartItem) => void
}

const StyledHeading = styled(Heading)`
  margin-bottom: 1.5rem;
`
const StyledContainer = styled.div`
  grid-template-columns: repeat(1, 1fr);
  gap: 24px;
  display: grid;
  padding-bottom: 3rem;

  @media ${breakpoints.M} {
    grid-template-columns: repeat(2, 1fr);
  }

  @media ${breakpoints.L} {
    grid-template-columns: repeat(3, 1fr);
  }
`

export const FoodSection = memo(
  ({ title, cartItems, items, onItemClick = () => {} }: FoodSectionProps) => (
    <div>
      <StyledHeading level={3}>{title}</StyledHeading>
      <StyledContainer>
        {items.map((item: FoodMenuItem) => {
          const cartItem = cartItems.find((c) => c.id === item.id)
          const quantity = cartItem?.quantity || 0
          return (
            <FoodItem
              key={item.name}
              name={item.name}
              price={item.price}
              description={item.description}
              quantity={quantity}
              onClick={() => onItemClick(item as CartItem)}
            />
          )
        })}
      </StyledContainer>
    </div>
  )
)
FoodSection.displayName = 'FoodSection'

